import React from 'react';
import {
	Dialog,
	DialogBody,
	DialogClose,
	DialogContent,
	DialogDescription,
	DialogFooter,
	DialogHeader,
	DialogTitle,
	DialogTrigger,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Share } from 'lucide-react';

export default function ShareDialog() {
	const [shareUrl] = React.useState('https://myapp.com/project/abc123');
	const [copied, setCopied] = React.useState(false);

	const copyToClipboard = () => {
		navigator.clipboard.writeText(shareUrl);
		setCopied(true);
		setTimeout(() => setCopied(false), 2000);
	};

	return (
		<Dialog>
			<DialogTrigger asChild>
				<Button variant="outline">Share Project</Button>
			</DialogTrigger>
			<DialogContent>
				<DialogHeader>
					<DialogTitle className="flex items-center justify-center sm:justify-start gap-2">
						<Share className="h-5 w-5" />
						Share Project
					</DialogTitle>
					<DialogDescription>Share this project with others</DialogDescription>
				</DialogHeader>
				<DialogBody>
					<div className="space-y-4">
						<div>
							<Label htmlFor="share-link">Project Link</Label>
							<div className="mt-2 flex gap-2">
								<Input
									id="share-link"
									value={shareUrl}
									readOnly
									className="flex-1"
								/>
								<Button
									onClick={copyToClipboard}
									variant="outline"
									className={copied ? 'text-green-600' : ''}
								>
									{copied ? 'Copied!' : 'Copy'}
								</Button>
							</div>
						</div>
						<div>
							<Label htmlFor="permissions">Permission Level</Label>
							<select
								id="permissions"
								className="mt-2 w-full rounded-md border p-2"
							>
								<option>Can view</option>
								<option>Can comment</option>
								<option>Can edit</option>
							</select>
						</div>
						<div>
							<Label htmlFor="invite-email">Invite by Email</Label>
							<div className="mt-2 flex gap-2">
								<Input
									id="invite-email"
									placeholder="colleague@company.com"
									className="flex-1"
								/>
								<Button>Send</Button>
							</div>
						</div>
					</div>
				</DialogBody>
				<DialogFooter>
					<DialogClose asChild>
						<Button variant="outline">Close</Button>
					</DialogClose>
				</DialogFooter>
			</DialogContent>
		</Dialog>
	);
}
